      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const { getTasks, createTask, updateTaskStatus } = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', (req, res) => {
  const statusFilter = req.query.status;
  const tasks = getTasks(req.projectId, statusFilter);
  if (tasks === null) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  res.json({ tasks });
});

router.post('/', (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_INPUT', 'Title is required');
  }
  const task = createTask(req.projectId, title);
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Status must be either todo or done');
  }
  const task = updateTaskStatus(req.projectId, req.params.taskId, status);
  if (task === null) {
    return sendError(res, 404, 'NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;
