      "path": "src/modules/comments/service.js",
      "content": "const projectsStore = require('../projects/store');

function getComments(projectId, taskId) {
  const project = projectsStore.getProjectById(projectId);
  if (!project) return null;
  const task = project.tasks.find(task => task.id === taskId);
  if (!task || !task.comments) return [];
  return task.comments;
}

function addComment(projectId, taskId, message) {
  const project = projectsStore.getProjectById(projectId);
  if (!project) return null;
  const task = project.tasks.find(task => task.id === taskId);
  if (!task) return null;
  if (!task.comments) task.comments = [];
  const newComment = { id: randomUUID(), message };
  task.comments.push(newComment);
  return newComment;
}

module.exports = { getComments, addComment };
